24	TriangleFiller::TriangleFiller(RenderTarget *target)
25	    :  fTarget(target),
26	       fTwoOverWidth(2.0f / target->getColorBuffer()->getWidth()),
27	       fTwoOverHeight(2.0f / target->getColorBuffer()->getHeight()),
28	       fOneOverZInterpolator()
29	{
30	}
31	
32	// Interpolated values are requested in screen space. If we linearily interpolate
33	// the values in screen space, they will not be perspective correct. Instead:
34	// 1. Divide parameter values by Z at each vertex.
35	// 2. Take the reciprocal of Z at each vertex
36	// 3. Perform linear interpolation in screen space of the values computed in 1 & 2
37	// 4. At each pixel, take the reciprocal of the linearly interpolated value from 2
38	//    to convert it to the Z value.
39	// 5. At each pixel, multiply each parameter by Z computed in step 4 to convert it back to
40	//    the perspective correct value.›
41	//
42	// See the paper "Perspective-Correct Interpolation" by Kok-Lim Low for a deeper description.
43	
44	void TriangleFiller::setUpTriangle(const RenderState *state,
45	                                   float x0, float y0, float z0,
46	                                   float x1, float y1, float z1,
47	                                   float x2, float y2, float z2)
48	{
49	    fState = state;
50	    fX0 = x0;
51	    fY0 = y0;
52	    fZ0 = z0;
53	    fZ1 = z1;
54	    fZ2 = z2;
55	
56	
57	    // The following system of equations describes the relationship
58	    // between the vertical and horizontal gradients (gx, gy),
59	    // the parameter values at each point (c0, c1, c2), and the
60	    // vertex positions in screen space coordinates (xn, yn):
61	    // | (x1-x0) (y1-y0) | | gx | = | (c1-c0) |
62	    // | (x2-x0) (y2-y0) | | gy |   | (c2-c0) |
63	    float a = x1 - x0;
64	    float b = y1 - y0;
65	    float c = x2 - x0;
66	    float d = y2 - y0;
67	
68	    // Invert the matrix from above to allow us to solve for the gradients for
69	    // any set of parameter values across this triangle. This is used in
70	    // setUpInterpolator.
71	    float oneOverDeterminant = 1.0 / (a * d - b * c);
72	    fInvGradientMatrix00 = d * oneOverDeterminant;
73	    fInvGradientMatrix10 = -c * oneOverDeterminant;
74	    fInvGradientMatrix01 = -b * oneOverDeterminant;
75	    fInvGradientMatrix11 = a * oneOverDeterminant;
76	
77	    if (fZ0 == fZ1 && fZ0 == fZ2)
78	        fNeedPerspective = false;
79	    else
80	    {
81	        fNeedPerspective = true;
82	
83	        // Compute one over Z for interpolation.
84	        setUpInterpolator(fOneOverZInterpolator, 1.0f / z0, 1.0f / z1, 1.0f / z2);
85	    }
86	
87	    fNumParams = 0;
88	}
89	
90	void TriangleFiller::setUpInterpolator(LinearInterpolator &interpolator, float c0, float c1,
91	                                       float c2)
92	{
93	    // Multiply by the matrix computed above to find gradients
94	    float e = c1 - c0;
95	    float f = c2 - c0;
96	    float xGradient = fInvGradientMatrix00 * e + fInvGradientMatrix01 * f;
97	    float yGradient = fInvGradientMatrix10 * e + fInvGradientMatrix11 * f;
98	
99	    // Compute c at 0, 0
100	    float c00 = c0 + -fX0 * xGradient + -fY0 * yGradient;
101	
102	    interpolator.init(xGradient, yGradient, c00);
103	}
104	
105	// c1, c2, and c2 represent the value of the parameter at the three
106	// triangle points specified in setUpTriangle.
107	void TriangleFiller::setUpParam(float c0, float c1, float c2)
108	{
109	    if (c0 == c1 && c0 == c2)
110	    {
111	        // If this is a constant, we can skip interpolation.
112	        fParameters[fNumParams].isConstant = true;
113	        fParameters[fNumParams].constantValue = c0;
114	    }
115	    else if (fNeedPerspective)
116	    {
117	        // Perspective interpolator.
118	        // These must be divided by Z to be perspective correct, as described above.
119	        fParameters[fNumParams].isConstant = false;
120	        setUpInterpolator(fParameters[fNumParams].linearInterpolator,
121	                          c0 / fZ0, c1 / fZ1, c2 / fZ2);
122	    }
123	    else
124	    {
125	        // Non-perspective interpolator. If all Zs are the same, we can just do linear
126	        // interpolation and save extra divisions.
127	        fParameters[fNumParams].isConstant = false;
128	        setUpInterpolator(fParameters[fNumParams].linearInterpolator,
129	                          c0, c1, c2);
130	    }
131	
132	    fNumParams++;
133	}
134	
135	void TriangleFiller::fillMasked(int left, int top, vmask_t mask)
136	{
137	    // Convert from raster to screen space coordinates.
138	    vecf16_t x = fTarget->getColorBuffer()->getXStep() + (left * fTwoOverWidth - 1.0f);
139	    vecf16_t y = 1.0f - top * fTwoOverHeight - fTarget->getColorBuffer()->getYStep();
140	
141	    // Depth buffer
142	    vecf16_t zValues;
143	    if (fNeedPerspective)
144	        zValues = 1.0f / fOneOverZInterpolator.getValuesAt(x, y);
145	    else
146	        zValues = fZ0;
147	
148	    if (fState->fEnableDepthBuffer)
149	    {
150	        vecf16_t depthBufferValues = vecf16_t(fTarget->getDepthBuffer()->readBlock(left, top));
151	        int passDepthTest = __builtin_nyuzi_mask_cmpf_gt(zValues, depthBufferValues);
152	
153	        // Early Z optimization: any pixels that fail the Z test are removed
154	        // from the pixel mask.
155	        mask &= passDepthTest;
156	        if (mask == 0)
157	            return; // All pixels are occluded
158	
159	        fTarget->getDepthBuffer()->writeBlockMasked(left, top, mask, vecu16_t(zValues));
160	    }
161	
162	    // Interpolate parameters
163	    vecf16_t interpolatedParams[kMaxParams];
164	    for (int paramIndex = 0; paramIndex < fNumParams; paramIndex++)
165	    {
166	        if (fParameters[paramIndex].isConstant)
167	            interpolatedParams[paramIndex] = fParameters[paramIndex].constantValue;
168	        else if (fNeedPerspective)
169	        {
170	            interpolatedParams[paramIndex] = fParameters[paramIndex].linearInterpolator
171	                                             .getValuesAt(x, y) * zValues;
172	        }
173	        else
174	        {
175	            interpolatedParams[paramIndex] = fParameters[paramIndex].linearInterpolator
176	                                             .getValuesAt(x, y);
177	        }
178	    }
179	
180	    // Shade
181	    vecf16_t color[4];
182	    fState->fShader->shadePixels(color, interpolatedParams, fState->fUniforms, fState->fTextures,
183	                                 mask);
184	
185	
186	    vecu16_t pixelValues;
187	
188	    Surface *destSurface = fTarget->getColorBuffer();
189	    switch (destSurface->getColorSpace())
190	    {
191	        case Surface::RGBA8888:
192	        {
193	            // Convert color channels to 8bpp
194	            vecu16_t rS = __builtin_convertvector(clamp(color[kColorR], 0.0, 1.0) * 255.0f, vecu16_t);
195	            vecu16_t gS = __builtin_convertvector(clamp(color[kColorG], 0.0, 1.0) * 255.0f, vecu16_t);
196	            vecu16_t bS = __builtin_convertvector(clamp(color[kColorB], 0.0, 1.0) * 255.0f, vecu16_t);
197	
198	            // If all pixels are fully opaque, don't bother trying to blend them.
199	            if (fState->fEnableBlend
200	                    && (__builtin_nyuzi_mask_cmpf_lt(color[kColorA], vecf16_t(1.0f)) & mask) != 0)
201	            {
202	                vecu16_t aS = __builtin_convertvector(clamp(color[kColorA], 0.0, 1.0) * 255.0f, vecu16_t)
203	                              & 0xff;
204	                vecu16_t oneMinusAS = 255 - aS;
205	
206	                vecu16_t destColors = vecu16_t(fTarget->getColorBuffer()->readBlock(left, top));
207	                vecu16_t rD = destColors & 0xff;
208	                vecu16_t gD = (destColors >> 8) & 0xff;
209	                vecu16_t bD = (destColors >> 16) & 0xff;
210	
211	                // Premultiplied alpha
212	                vecu16_t newR = saturate(((rS << 8) + (rD * oneMinusAS)) >> 8, 255);
213	                vecu16_t newG = saturate(((gS << 8) + (gD * oneMinusAS)) >> 8, 255);
214	                vecu16_t newB = saturate(((bS << 8) + (bD * oneMinusAS)) >> 8, 255);
215	                pixelValues = 0xff000000 | newR | (newG << 8) | (newB << 16);
216	            }
217	            else
218	                pixelValues = 0xff000000 | rS | (gS << 8) | (bS << 16);
219	
220	            break;
221	        }
222	
223	        case Surface::FLOAT:
224	            // Just store channel 0 as a floating point value. Hack?
225	            pixelValues = vecu16_t(color[0]);
226	            break;
227	
228	        default:
229	            assert(0);  // Not supported yet
230	    }
231	
232	    destSurface->writeBlockMasked(left, top, mask, vecu16_t(pixelValues));
233	}
